    responses: [
      {
        stdout: verifierProviderResult(
          "codex-story-verify-disagreement-001",
          baseVerifierPayload(fixture)
        ),
      },
    ],
  });
  const claudeProvider = await writeFakeProviderExecutable({
    binDir: providerBinDir,
    provider: "claude",
