                affectedFiles: ["processes/impl-cli/commands/story-verify.ts"],
                requirementIds: ["TC-5.2c"],
                recommendedFixScope: "fresh-fix-path",
                blocking: false,
              },
            ],
            requirementCoverage: {
              verified: ["AC-5.1", "TC-5.1a"],
              unverified: ["TC-5.2c"],
            },
          })
        ),
      },
    ],
